import torch

class FakeQuantize(torch.autograd.Function):
    """Fake quantization with Straight-Through Estimator."""

    @staticmethod
    def forward(ctx, W: torch.Tensor, scale: float, bits: int = 8) -> torch.Tensor:
        max_int = 2 ** (bits - 1) - 1
        W_scaled = W / scale
        W_clipped = W_scaled.clamp(-max_int - 1, max_int)
        ctx.save_for_backward(W_scaled)
        ctx.max_int = max_int
        # Quantize and dequantize — stays in FP32 but carries only b-bit info
        return W_clipped.round() * scale

    @staticmethod
    def backward(ctx, grad_output: torch.Tensor):
        W_scaled, = ctx.saved_tensors
        # STE: pass gradient through, zero out where clamped
        in_range = (W_scaled.abs() <= ctx.max_int).float()
        return grad_output * in_range, None, None   # None for scale, bits

fake_quantize = FakeQuantize.apply

# Usage inside a custom linear layer:
class QATLinear(torch.nn.Linear):
    def __init__(self, *args, bits: int = 8, **kwargs):
        super().__init__(*args, **kwargs)
        self.bits = bits
        self.register_buffer("scale", torch.ones(1))

    def update_scale(self):
        self.scale = (self.weight.abs().max() / (2 ** (self.bits - 1) - 1)).detach()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        self.update_scale()
        quantized_weight = fake_quantize(self.weight, self.scale.item(), self.bits)
        return torch.nn.functional.linear(x, quantized_weight, self.bias)
